import { create } from 'zustand';

interface AttendanceState {
  hasPunchedIn: boolean;
  hasPunchedOut: boolean;
  punchInTime: string | null;
  punchOutTime: string | null;
  punchIn: () => void;
  punchOut: () => void;
  resetDaily: () => void;
}

export const useAttendanceStore = create<AttendanceState>((set) => ({
  hasPunchedIn: false,
  hasPunchedOut: false,
  punchInTime: null,
  punchOutTime: null,
  punchIn: () => set({ hasPunchedIn: true, punchInTime: new Date().toISOString() }),
  punchOut: () => set({ hasPunchedOut: true, punchOutTime: new Date().toISOString() }),
  resetDaily: () => set({ hasPunchedIn: false, hasPunchedOut: false, punchInTime: null, punchOutTime: null }),
}));
